import React, {useState} from "react";
import './Welcome.css';
import axios from 'axios'
import { useNavigate } from "react-router-dom";
import { useAuth } from "./auth";

function Welcome () {


    const [userName, setUserName] = useState('');
    const [passWord, setPassWord] = useState('');
    const [isLoginSuccessful, setIsLoginSuccessful] = useState(false);
    const [invalidCreds, setInvalidCreds] = useState(false);
    const [response, setResponse] = useState('');
    const navigate = useNavigate();
    const handleUsernameChange = (e) => {
        e.preventDefault();
        const value = e.target.value;
        setUserName(value);
    }
    const handlePasswordChange = (e) => {
        e.preventDefault();
        const value = e.target.value;
        setPassWord(value);
    }
    const auth = useAuth();
    const Login = (e) => {
        e.preventDefault();
        auth.login(userName)
        if (userName === 'Admin' && passWord === '1234') {
            setIsLoginSuccessful(true);
            setInvalidCreds(false);
            Credentials(isLoginSuccessful);
            navigate('welcome', {replace: true })
            let username = 'user';
            let password = '1234';
            let basicAuthHeader = 'Basic ' + window.btoa(username + ':' + password);
            axios.get(`http://localhost:8080/users/Admin/items`, {
                headers: {
                    Authorization: basicAuthHeader
            }
        }
            ).then(response => console.log(response.data))
            .catch(error => setIsLoginSuccessful(false)); // Fix this for an error pafe backend and not condtionals, 404 or 500 error via axious.
        }
        else {
            setInvalidCreds(true);
            InvalidCredentials(invalidCreds);
            setIsLoginSuccessful(false);
            Credentials(isLoginSuccessful);
        }
    }
    const Credentials = () => {
        if (isLoginSuccessful)  
        {  
            return response;
        }
    }
    const InvalidCredentials = () => {
        if (invalidCreds)  
        {  
            return (
                        <div className="error-message">Invalid Credential!</div>
                    )
        }
    }
    return  (
        <form>
        <div class="form-group">
            <label for="exampleInputEmail1">Email address</label>
            <input type="email" class="form-control" id="exampleInputEmail1" aria-describedby="emailHelp" placeholder="Enter email"></input>
            <small id="emailHelp" class="form-text text-muted">We'll never share your email with anyone else.</small>
        </div>
        <div class="form-group">
            <label for="exampleInputPassword1">Password</label>
            <input type="password" class="form-control" id="exampleInputPassword1" placeholder="Password"></input>
        </div>
        <div class="form-group form-check">
        </div>
        <button type="submit" class="btn btn-primary">Submit</button>
        </form>


            // <InvalidCredentials/>
            // <Credentials/>

    )
    }

export default Welcome;
